import React, { useEffect, useState, useRef } from 'react';

// This component uses socket.io-client. Install with:
// npm install socket.io-client

export default function ChatSocket({ serverUrl = 'http://localhost:3001', user, token }) {
  const [socket, setSocket] = useState(null);
  const [messages, setMessages] = useState([]);
  const [presence, setPresence] = useState([]);
  const [text, setText] = useState('');
  const messagesRef = useRef(null);

  useEffect(() => {
    let ioClient;
    try {
      // lazy require to avoid crash when dependency missing
      // eslint-disable-next-line global-require
      const { io } = require('socket.io-client');
      const auth = (typeof token !== 'undefined' && token) ? { token } : undefined;
      ioClient = io(serverUrl, { transports: ['websocket', 'polling'], auth });
      setSocket(ioClient);

      ioClient.on('connect', () => {
        console.log('Connected to socket server', ioClient.id);
        // fetch recent messages
        fetch(`${serverUrl}/api/messages?limit=50`)
          .then(r => r.json())
          .then(data => {
            if (data && Array.isArray(data.messages)) {
              setMessages(data.messages);
            }
          })
          .catch(err => console.warn('Failed to load messages', err));
      });

      ioClient.on('message', (m) => {
        setMessages((prev) => [...prev, m]);
        // Show notification for new messages
        if (Notification.permission === 'granted') {
          new Notification('Tin nhắn mới', {
            body: m.text,
            icon: '/favicon.ico'
          });
        } else if (Notification.permission !== 'denied') {
          Notification.requestPermission().then(permission => {
            if (permission === 'granted') {
              new Notification('Tin nhắn mới', {
                body: m.text,
                icon: '/favicon.ico'
              });
            }
          });
        }
      });

      ioClient.on('presence', (list) => {
        setPresence(list || []);
      });
    } catch (err) {
      console.warn('socket.io-client not installed; chat disabled. Run: npm install socket.io-client');
    }

    return () => {
      if (ioClient) ioClient.disconnect();
    };
  }, [serverUrl, user, token]);

  useEffect(() => {
    if (messagesRef.current) {
      messagesRef.current.scrollTop = messagesRef.current.scrollHeight;
    }
  }, [messages]);

  const send = () => {
    if (!socket || !text) return;
    const msg = { from: user || { id: socket.id, display_name: 'Guest' }, text };
    socket.emit('message', msg);
    setMessages((prev) => [...prev, msg]);
    setText('');
  };

  return (
    <div className="fixed bottom-5 right-5 w-[300px] bg-white border border-gray-300 rounded-lg shadow-lg flex flex-col">
      <div className="bg-blue-500 text-white px-4 py-2 rounded-t-lg font-semibold">
        Chat với bạn bè
      </div>
      <div className="flex-1 p-2 flex flex-col gap-2 max-h-[300px] overflow-y-auto">
        {messages.map((m, i) => (
          <div key={i} className="text-black text-sm bg-gray-100 px-2 py-1 rounded-md">
            {m.text}
          </div>
        ))}
      </div>
      <div className="flex border-t border-gray-300">
        <input
          className="flex-1 px-2 py-1 outline-none"
          placeholder="Nhập tin nhắn..."
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") send();
          }}
        />
        <button
          className="px-4 bg-blue-500 text-white rounded-r-lg"
          onClick={send}
        >
          Gửi
        </button>
      </div>
    </div>
  );
}
